1	//! First-run wizard panels.
2	//!
3	//! show_wizard() is the entry point. It dispatches to the correct step panel
4	//! based on first_incomplete_step(), re-probes after each action, and signals
5	//! completion when is_setup_complete() is true.
6	//!
7	//! All panels are feature-gated to `gui` — only compiled when eframe is present.
8	
9	/// Re-export all wizard types and the `show_wizard` entry point when the `gui` feature is enabled.
10	#[cfg(feature = "gui")]
11	pub use inner::*;
12	
