29	    // ── Download state ───────────────────────────────────────────────────────
30	
31	    /// Progress state of the background model download.
32	    #[derive(Debug, Clone, PartialEq)]
33	    pub enum DownloadStatus {
34	        /// No download in progress.
35	        Idle,
36	        /// Download underway; `total` is `None` when the server omits Content-Length.
37	        Downloading { received: u64, total: Option<u64> },
38	        /// Download finished and the file has been moved into place.
39	        Done,
40	        /// Download failed; the inner string is a human-readable error message.
41	        Failed(String),
42	    }
43	
44	    /// Shared state for the model download background thread.
45	    pub struct ModelDownloadState {
46	        /// Current download progress, shared with the download thread via `Arc<Mutex<_>>`.
47	        pub status: Arc<Mutex<DownloadStatus>>,
48	        /// Join handle for the download thread; `None` when no download is running.
49	        pub handle: Option<std::thread::JoinHandle<()>>,
50	    }
51	
52	    impl ModelDownloadState {
53	        /// Construct initial state with `Idle` status and no thread handle.
54	        pub fn new() -> Self {
55	            Self {
56	                status: Arc::new(Mutex::new(DownloadStatus::Idle)),
57	                handle: None,
58	            }
59	        }
60	
61	        /// Return a clone of the current download status without blocking on failure.
62	        pub fn current(&self) -> DownloadStatus {
63	            self.status.lock().map(|g| g.clone()).unwrap_or(DownloadStatus::Idle)
64	        }
65	
66	        /// True while the download thread is actively transferring bytes.
67	        pub fn is_running(&self) -> bool {
68	            matches!(self.current(), DownloadStatus::Downloading { .. })
69	        }
70	    }
71	
72	    impl Default for ModelDownloadState {
73	        fn default() -> Self {
74	            Self::new()
75	        }
76	    }
