80	    /// Lifecycle state of a single privileged uinput setup action (modprobe or usermod).
81	    #[derive(Debug, Clone, PartialEq)]
82	    pub enum SetupActionStatus {
83	        /// Action has not been initiated yet.
84	        Idle,
85	        /// pkexec subprocess is running; poll the thread handle to detect completion.
86	        Running,
87	        /// Action completed successfully.
88	        Done,
89	        /// Action failed; the inner string is a human-readable error message.
90	        Failed(String),
91	    }
