167	    /// Render the wizard panel for the current incomplete step.
168	    ///
169	    /// Returns an updated `FirstRunState` — call probe::run() after actions.
170	    /// If setup is complete, returns the current state unchanged.
171	    pub fn show_wizard(
172	        ui: &mut egui::Ui,
173	        state: &mut FirstRunState,
174	        ptt: &mut PttCaptureState,
175	        dl: &mut ModelDownloadState,
176	        uinput: &mut UinputSetupState,
177	        config_example_contents: &str,
178	        hd2_profile_contents: &str,
179	    ) {
180	        // Harvest PTT result from background thread if ready
181	        if ptt.listening && ptt.has_result() {
182	            if let Some(key_name) = ptt.take_result() {
183	                ptt.listening = false;
184	                match write_ptt_key_to_config(&key_name) {
185	                    Ok(()) => {
186	                        info!(key = %key_name, "PTT key written to config");
187	                        *state = probe::run();
188	                    }
189	                    Err(e) => {
190	                        error!(key = %key_name, reason = %e, "Failed to write PTT key to config");
191	                        ptt.error = Some(format!("Failed to save key: {e}"));
192	                    }
193	                }
194	            }
195	        }
196	
197	        // Reap finished thread handle to avoid leaking it
198	        if let Some(h) = &ptt.handle {
199	            if h.is_finished() {
200	                if let Some(handle) = ptt.handle.take() {
201	                    let _ = handle.join();
202	                }
203	            }
204	        }
205	
206	        // Re-probe after download completes, then reap the handle.
207	        if let Some(h) = &dl.handle {
208	            if h.is_finished() {
209	                if let Ok(DownloadStatus::Done) = dl.status.lock().map(|g| g.clone()) {
210	                    *state = probe::run();
211	                }
212	                if let Some(handle) = dl.handle.take() {
213	                    let _ = handle.join();
214	                }
215	            }
216	        }
217	
218	        // Harvest modprobe and usermod thread results.
219	        if let Some(h) = &uinput.modprobe_handle {
220	            if h.is_finished() {
221	                if let Some(handle) = uinput.modprobe_handle.take() {
222	                    uinput.modprobe = match handle.join() {
223	                        Ok(Ok(())) => SetupActionStatus::Done,
224	                        Ok(Err(e)) => SetupActionStatus::Failed(e),
225	                        Err(_) => SetupActionStatus::Failed("thread panicked".to_string()),
226	                    };
227	                    *state = probe::run();
228	                }
229	            }
230	        }
231	        if let Some(h) = &uinput.usermod_handle {
232	            if h.is_finished() {
233	                if let Some(handle) = uinput.usermod_handle.take() {
234	                    uinput.usermod = match handle.join() {
235	                        Ok(Ok(())) => SetupActionStatus::Done,
236	                        Ok(Err(e)) => SetupActionStatus::Failed(e),
237	                        Err(_) => SetupActionStatus::Failed("thread panicked".to_string()),
238	                    };
239	                    *state = probe::run();
240	                }
241	            }
242	        }
243	
244	        match state.first_incomplete_step() {
245	            None => {
246	                ui.heading("Setup complete");
247	                ui.label("All prerequisites satisfied. Loading config app…");
248	            }
249	            Some(SetupStep::CreateConfig) => {
250	                show_create_config(ui, state, config_example_contents, hd2_profile_contents);
251	            }
252	            Some(SetupStep::InstallModel) => {
253	                show_install_model(ui, state, dl);
254	            }
255	            Some(SetupStep::SetupUinput) => {
256	                show_setup_uinput(ui, state, uinput);
257	            }
258	            Some(SetupStep::ConfigurePtt) => {
259	                show_configure_ptt(ui, state, ptt);
260	            }
261	        }
262	    }
