403	    /// Download the model file to `dest`, streaming progress into `status`.
404	    fn download_model(status: Arc<Mutex<DownloadStatus>>, dest: &str) {
405	        info!(url = MODEL_URL, dest, "starting model download");
406	
407	        let dest_path = PathBuf::from(dest);
408	        if let Some(parent) = dest_path.parent() {
409	            if let Err(e) = std::fs::create_dir_all(parent) {
410	                error!(reason = %e, "failed to create model directory");
411	                if let Ok(mut g) = status.lock() {
412	                    *g = DownloadStatus::Failed(format!("mkdir failed: {e}"));
413	                }
414	                return;
415	            }
416	        }
417	
418	        let response = match ureq::get(MODEL_URL).call() {
419	            Ok(r) => r,
420	            Err(e) => {
421	                error!(reason = %e, "model download request failed");
422	                if let Ok(mut g) = status.lock() {
423	                    *g = DownloadStatus::Failed(e.to_string());
424	                }
425	                return;
426	            }
427	        };
428	
429	        let total = response
430	            .header("content-length")
431	            .and_then(|v| v.parse::<u64>().ok());
432	
433	        // Write to a temp file alongside the destination, then rename atomically.
434	        let tmp_path = dest_path.with_extension("tmp");
435	        let mut file = match std::fs::File::create(&tmp_path) {
436	            Ok(f) => f,
437	            Err(e) => {
438	                error!(reason = %e, "failed to create temp file");
439	                if let Ok(mut g) = status.lock() {
440	                    *g = DownloadStatus::Failed(format!("file create failed: {e}"));
441	                }
442	                return;
443	            }
444	        };
445	
446	        let mut reader = response.into_reader();
447	        let mut buf = vec![0u8; 65536];
448	        let mut received: u64 = 0;
449	
450	        loop {
451	            match reader.read(&mut buf) {
452	                Ok(0) => break,
453	                Ok(n) => {
454	                    use std::io::Write;
455	                    if let Err(e) = file.write_all(&buf[..n]) {
456	                        error!(reason = %e, "write error during download");
457	                        let _ = std::fs::remove_file(&tmp_path);
458	                        if let Ok(mut g) = status.lock() {
459	                            *g = DownloadStatus::Failed(format!("write error: {e}"));
460	                        }
461	                        return;
462	                    }
463	                    received += n as u64;
464	                    if let Ok(mut g) = status.lock() {
465	                        *g = DownloadStatus::Downloading { received, total };
466	                    }
467	                }
468	                Err(e) => {
469	                    error!(reason = %e, "read error during download");
470	                    let _ = std::fs::remove_file(&tmp_path);
471	                    if let Ok(mut g) = status.lock() {
472	                        *g = DownloadStatus::Failed(format!("read error: {e}"));
473	                    }
474	                    return;
475	                }
476	            }
477	        }
478	
479	        if let Err(e) = std::fs::rename(&tmp_path, &dest_path) {
480	            error!(reason = %e, "failed to rename tmp file");
481	            let _ = std::fs::remove_file(&tmp_path);
482	            if let Ok(mut g) = status.lock() {
483	                *g = DownloadStatus::Failed(format!("rename failed: {e}"));
484	            }
485	            return;
486	        }
487	
488	        info!(dest, bytes = received, "model download complete");
489	        if let Ok(mut g) = status.lock() {
490	            *g = DownloadStatus::Done;
491	        }
492	    }
