581	    /// Run a command via pkexec (polkit) and return Ok(()) on exit 0, Err(msg) otherwise.
582	    fn run_pkexec(args: &[&str]) -> Result<(), String> {
583	        let mut cmd_args = vec!["pkexec"];
584	        cmd_args.extend_from_slice(args);
585	
586	        let status = std::process::Command::new(cmd_args[0])
587	            .args(&cmd_args[1..])
588	            .status()
589	            .map_err(|e| format!("failed to run pkexec: {e}"))?;
590	
591	        if status.success() {
592	            Ok(())
593	        } else {
594	            Err(format!(
595	                "command exited with code {}",
596	                status.code().unwrap_or(-1)
597	            ))
598	        }
599	    }
