623	    fn show_configure_ptt(
624	        ui: &mut egui::Ui,
625	        state: &mut FirstRunState,
626	        ptt: &mut PttCaptureState,
627	    ) {
628	        ui.heading("Step 4 of 4: Configure PTT key");
629	        ui.add_space(8.0);
